export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:25。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館側廊。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "和上一輪一樣的廊。一樣的浪板頂。一樣的積水。一樣的灰。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有靠在柱子後面。他站在廊中間。背對著主樓方向，面朝校史館側門。雙手插在口袋裡。等。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）上一輪我攔住她，說她會死。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她退了半步，手按住相機包，把我當成來搶東西的人。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪不說那三個字。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不說「妳會死」。不說「23:00」。不說「黑雨衣」。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那些詞只會讓她後退。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不記得上一輪。對她來說，今天是第一次見我站在這裡。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）所以我得用她自己的東西——用只有和她合作過的人才會知道的東西——讓她停下來。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲從主樓方向過來。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不急。但很穩。膠底鞋踩過積水的節奏太均勻了——每一步的落點都像被量過。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是她。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從轉角出現。攝影背心，藍色工作證，相機包斜挎在身側。她低著頭看手機，碎髮被濕氣黏在耳側。走得快，但上半身幾乎不晃。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抬起頭的時候，看見廊中間站了一個人。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停下來。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的眼睛對上他的那一秒，顧言看見的不是驚訝。是和上一輪一模一樣的凝視——像在調焦距。瞳仁很亮，但那種亮不是熱的。是深水面的反光。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要急。不要搶。一個字一個字給。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "空包不是失誤。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得很平。像在唸一行課文。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "那個空的相機包。妳拿它走裝卸區，是餌。用來釣攔截線的人。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的表情沒有變。但她停下了往後退的動作——那個動作還沒開始就被這句話按住了。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有退。上一輪她聽到「妳會死」就退了。這一次她沒有。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為這不是預言。這是她自己的計畫。只有她自己和她身邊的人知道。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "加密檔。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "檔名裡有 GZ。後面是「給小言」。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見她的手指動了一下。在相機包的帶子上。很小的收緊。像聽到了一個不該從這個人嘴裡出來的詞。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你從哪裡知道這些。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是質問。聲音平得像剛刷過漆的牆。和上一輪一樣的聲音。一樣的節制。一樣的控制。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她問了。上一輪她也問了同一句。但上一輪她問的時候已經退了半步。這一次她站在原地。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）差別在——上一輪我丟的是「妳會死」。這一輪我丟的是她自己的東西。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我說時間循環，妳不會信。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳也不該立刻信。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "所以這一輪，我不要求妳信我。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我只要求妳看結果。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廊裡只有雨聲。浪板頂上的水往下淌。常綠盆栽的葉子積了一層水，一滴一滴地落在地上。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著他。看了很久。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那雙深水的眼睛底下有什麼在動——不是信任。也不是恐懼。是一種很冷的、在計算的東西。她在秤。秤他說的這些話值多少重量。秤他到底是什麼人。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你知道空包。你知道檔名。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這些不是公開資訊。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在篩。和上一輪一樣。哪些是公開的，哪些不是。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這一次她篩完之後沒有退。她在等下一句。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你說林主任不是終點。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她接了他的話。不是問句。是陳述。像在替他把句子唸完，然後看他的反應。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不是。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "那這一輪——", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "別告訴我答案。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "告訴我你要怎麼證明。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音沒有升高。沒有降低。每一個字都發音清楚，像刻意控制過的音量——不會大到被第三個人聽見，也不會小到讓他聽不清。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有問「為什麼」。沒有問「你怎麼知道」。沒有問「你是誰的人」。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她直接跳到方法。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）上一輪我花了一整天才走到這一步。這一輪——兩句話。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為我沒有再把她當成一個需要被說服的人。我把她當成一個已經在調查的人。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她本來就是。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "八點。舊圖書室旁邊的暗房。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "那裡沒有監視器。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有點頭。也沒有搖頭。她只是看了他最後一眼——那種深水的、在秤重量的凝視——然後把相機包的帶子往肩上提了一下。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從他身邊走過去。走進校史館側門。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有回頭。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廊裡又只剩他一個人。雨聲。浪板。積水。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她會來。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為她不是在等我救她。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在等我證明。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯這就夠了。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.GuYan_Determined },
];
